(window.webpackJsonp=window.webpackJsonp||[]).push([[1127],{1086:function(n){n.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\"># The guess API is already defined for you.</span>\\n<span class=\\"hljs-comment\\"># @param num, your guess</span>\\n<span class=\\"hljs-comment\\"># @return -1 if my number is lower, 1 if my number is higher, otherwise return 0</span>\\n<span class=\\"hljs-comment\\"># def guess(num):</span>\\n\\n<span class=\\"hljs-class\\"><span class=\\"hljs-keyword\\">class</span> <span class=\\"hljs-title\\">Solution</span><span class=\\"hljs-params\\">(object)</span>:</span>\\n    <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">def</span> <span class=\\"hljs-title\\">guessNumber</span><span class=\\"hljs-params\\">(self, n)</span>:</span>\\n        <span class=\\"hljs-string\\">\\"\\"\\"\\n        :type n: int\\n        :rtype: int\\n        \\"\\"\\"</span>\\n        lo,hi=<span class=\\"hljs-number\\">1</span>,n\\n        <span class=\\"hljs-keyword\\">while</span> lo&lt;hi:\\n          mid=(lo+hi)//<span class=\\"hljs-number\\">2</span>\\n          res=guess(mid)\\n          <span class=\\"hljs-keyword\\">if</span> res==<span class=\\"hljs-number\\">1</span>:\\n            lo=mid+<span class=\\"hljs-number\\">1</span>\\n          <span class=\\"hljs-keyword\\">else</span>:\\n            hi=mid\\n        <span class=\\"hljs-keyword\\">return</span> lo\\n</code></pre>\\n"],"titleSlug":"guess-number-higher-or-lower","hasThinking":false,"content":"<p>\u731c\u6570\u5b57\u6e38\u620f\u7684\u89c4\u5219\u5982\u4e0b\uff1a</p>\\n\\n<ul>\\n\\t<li>\u6bcf\u8f6e\u6e38\u620f\uff0c\u6211\u90fd\u4f1a\u4ece\xa0<strong>1</strong>\xa0\u5230\xa0<em><strong>n</strong></em> \u968f\u673a\u9009\u62e9\u4e00\u4e2a\u6570\u5b57\u3002 \u8bf7\u4f60\u731c\u9009\u51fa\u7684\u662f\u54ea\u4e2a\u6570\u5b57\u3002</li>\\n\\t<li>\u5982\u679c\u4f60\u731c\u9519\u4e86\uff0c\u6211\u4f1a\u544a\u8bc9\u4f60\uff0c\u4f60\u731c\u6d4b\u7684\u6570\u5b57\u6bd4\u6211\u9009\u51fa\u7684\u6570\u5b57\u662f\u5927\u4e86\u8fd8\u662f\u5c0f\u4e86\u3002</li>\\n</ul>\\n\\n<p>\u4f60\u53ef\u4ee5\u901a\u8fc7\u8c03\u7528\u4e00\u4e2a\u9884\u5148\u5b9a\u4e49\u597d\u7684\u63a5\u53e3 <code>int guess(int num)</code> \u6765\u83b7\u53d6\u731c\u6d4b\u7ed3\u679c\uff0c\u8fd4\u56de\u503c\u4e00\u5171\u6709 3 \u79cd\u53ef\u80fd\u7684\u60c5\u51b5\uff08<code>-1</code>\uff0c<code>1</code>\xa0\u6216 <code>0</code>\uff09\uff1a</p>\\n\\n<ul>\\n\\t<li>-1\uff1a\u6211\u9009\u51fa\u7684\u6570\u5b57\u6bd4\u4f60\u731c\u7684\u6570\u5b57\u5c0f <code>pick < num</code></li>\\n\\t<li>1\uff1a\u6211\u9009\u51fa\u7684\u6570\u5b57\u6bd4\u4f60\u731c\u7684\u6570\u5b57\u5927 <code>pick > num</code></li>\\n\\t<li>0\uff1a\u6211\u9009\u51fa\u7684\u6570\u5b57\u548c\u4f60\u731c\u7684\u6570\u5b57\u4e00\u6837\u3002\u606d\u559c\uff01\u4f60\u731c\u5bf9\u4e86\uff01<code>pick == num</code></li>\\n</ul>\\n\\n<p>\u8fd4\u56de\u6211\u9009\u51fa\u7684\u6570\u5b57\u3002</p>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>n = 10, pick = 6\\n<strong>\u8f93\u51fa\uff1a</strong>6\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>n = 1, pick = 1\\n<strong>\u8f93\u51fa\uff1a</strong>1\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>n = 2, pick = 1\\n<strong>\u8f93\u51fa\uff1a</strong>1\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 4\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>n = 2, pick = 2\\n<strong>\u8f93\u51fa\uff1a</strong>2\\n</pre>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>1 <= n <= 2<sup>31</sup> - 1</code></li>\\n\\t<li><code>1 <= pick <= n</code></li>\\n</ul>\\n","title":"374. \u731c\u6570\u5b57\u5927\u5c0f","relatedTags":["\u4e8c\u5206\u67e5\u627e"],"difficult":"Easy","lang":["python"],"uniqueID":"374"}')}}]);